import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { HashLink } from 'react-router-hash-link';

function Navigation() {
  const location = useLocation();

  const navItems = [
    { name: '主頁', nameEn: 'Home', path: '#home', type: 'hash'},
    { name: '介紹', nameEn: 'Intro', path: '#intro', type: 'hash'},
    { name: '搜卡', nameEn: 'Search', path: '#search', type: 'hash'},
  ];

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <HashLink smooth to="/#home" className="navbar-logo">
          <img className="logo-img" src="data:image/png;base64," alt="寶可夢卡牌查詢" />
        </HashLink>
        <div className="navbar-menu">
          {navItems.map((item) => 
            item.type === 'hash' ? (
            <HashLink
              key={item.path}
              smooth
              to={`/${item.path}`}
              className={`navbar-item ${location.hash === item.path ? 'active' : ''}`}
            >
              <span className="nav-text-zh">{item.name}</span>
              <span className="nav-text-en">{item.nameEn}</span>
            </HashLink>
          ) : (
              <Link key={item.path} to={item.path} className={`navbar-item ${location.pathname === item.path ? 'active' : ''}`} >
                <span className="nav-text-zh">{item.name}</span>
                <span className="nav-text-en">{item.nameEn}</span>
              </Link>
            )
          )}
        </div>
      </div>
    </nav>
  );
}

export default Navigation;
